sql:
SELECT COUNT(*) AS total_counties_above_avg_density
FROM counties AS c
JOIN population_data AS pd ON c.county_id = pd.county_id
WHERE pd.population_density > (
    SELECT AVG(population_density) FROM population_data
);

SELECT county_name 
FROM counties 
WHERE state_id = (SELECT level_id FROM geographic_levels WHERE level_name = 'California');

SELECT SUM(population) AS total_population
FROM population_data
WHERE county_id = (SELECT county_id FROM counties WHERE county_name = 'Big Horn');
